tool.command:
if tiffinfo $input_image | grep "Compression Scheme:" | grep -wq "JPEG";
then
    if od -h -j2 -N2 $input_image | head -n1 | sed 's/[0-9]*  *//' | grep -q -E '002b|2b00';
    then
        tiffcp -c none -m 0 -8 $input_image uncompressed.tif;
    else
        tiffcp -c none -m 0 $input_image uncompressed.tif || tiffcp -c none -m 0 -8 $input_image uncompressed.tif;
    fi;
        bioformats2raw --no-hcs uncompressed.tif output.zarr;
else
    bioformats2raw --no-hcs $input_image output.zarr;
fi;
/usr/local/bin/consolidate_md.py --file_in output.zarr &&
zip -r output.zarr.zip output.zarr &&
mv output.zarr.zip $output_zarr
